mapper.select:
SELECT r.*, gvi.CONTENT AS NAME_VI, gen.CONTENT AS NAME_EN, gzh.CONTENT AS NAME_ZH, gko.CONTENT AS NAME_KO FROM SY_ROLE_GROUP r LEFT JOIN SY_GLOBAL_NAME gvi ON r.ROLE_GROUP_NO = gvi.NO AND gvi.LANGUAGE = 'vi' LEFT JOIN SY_GLOBAL_NAME gen ON r.ROLE_GROUP_NO = gen.NO AND gen.LANGUAGE = 'en' LEFT JOIN SY_GLOBAL_NAME gzh ON r.ROLE_GROUP_NO = gzh.NO AND gzh.LANGUAGE = 'zh' LEFT JOIN SY_GLOBAL_NAME gko ON r.ROLE_GROUP_NO = gko.NO AND gko.LANGUAGE = 'ko' WHERE 1=1 AND r.ACTIVITY = 1 AND r.CPNY_ID = #{cpnyId}
AND ( r.ROLE_GROUP_ID LIKE '%' || #{keyword} || '%' OR gvi.CONTENT LIKE '%' || #{keyword} || '%' OR gen.CONTENT LIKE '%' || #{keyword} || '%' OR gzh.CONTENT LIKE '%' || #{keyword} || '%' OR gko.CONTENT LIKE '%' || #{keyword} || '%' )
ORDER BY r.ORDERNO, r.ROLE_GROUP_ID

mapper.insert:
INSERT INTO SY_ROLE_GROUP (
    ROLE_GROUP_NO, ROLE_GROUP_ID, JOIN_DEFAULT, CPNY_ID,
    CREATE_DATE, CREATED_BY, UPDATE_DATE, UPDATED_BY,
    ORDERNO, ACTIVITY, SYS_TYPE
) VALUES (
    #{roleGroupNo}, #{roleGroupId}, #{joinDefault}, #{cpnyId},
    sysdate, #{adminID}, sysdate, #{adminID},
    #{orderNo}, #{activity}, #{sysType}
)
